<?php
namespace Tests\Feature\Admin\Content;use App\Models\RefinementStatModifier;use App\Models\User;use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class RefinementStatModifierAdminTest extends TestCase{use RefreshDatabase;private $admin;protected function setUp():void{parent::setUp();config(['game_admin.emails'=>['stats-admin@example.test']]);$this->admin=User::factory()->create(['email'=>'stats-admin@example.test']);}public function test_access_and_missing_level_warnings(){ $this->actingAs(User::factory()->create())->get(route('admin.content.refinement.index'))->assertForbidden();$this->actingAs($this->admin)->get(route('admin.content.refinement.index'))->assertOk()->assertSee('Bonus estadístico por nivel')->assertSee('Sin configuración estadística activa')->assertSee('Este porcentaje es el incremento total aplicado');}public function test_create_update_activate_and_deactivate_without_delete(){ $this->actingAs($this->admin)->post(route('admin.content.refinement.stats.store'),['refinement_level'=>3,'stat_increase_basis_points'=>3000,'status'=>'active'])->assertSessionHas('status','Modificador estadístico actualizado correctamente.');$modifier=RefinementStatModifier::firstOrFail();$this->put(route('admin.content.refinement.stats.update',$modifier),['refinement_level'=>3,'stat_increase_basis_points'=>3500,'status'=>'inactive'])->assertSessionHas('status','Modificador estadístico actualizado correctamente.');$this->assertSame(3500,$modifier->fresh()->stat_increase_basis_points);$this->patch(route('admin.content.refinement.stats.activate',$modifier))->assertSessionHas('status','Modificador estadístico activado correctamente.');$before=$modifier->fresh()->stat_increase_basis_points;$this->patch(route('admin.content.refinement.stats.deactivate',$modifier))->assertSessionHas('status','Modificador estadístico desactivado correctamente.');$this->assertSame($before,$modifier->fresh()->stat_increase_basis_points);$this->assertSame('inactive',$modifier->fresh()->status);$this->assertDatabaseHas('refinement_stat_modifiers',['id'=>$modifier->id]);}public function test_invalid_and_duplicate_values_are_rejected(){ $this->actingAs($this->admin);$this->post(route('admin.content.refinement.stats.store'),['refinement_level'=>1,'stat_increase_basis_points'=>1001,'status'=>'active'])->assertRedirect();$this->post(route('admin.content.refinement.stats.store'),['refinement_level'=>1,'stat_increase_basis_points'=>2000,'status'=>'active'])->assertSessionHasErrors('refinement_level');$this->post(route('admin.content.refinement.stats.store'),['refinement_level'=>16,'stat_increase_basis_points'=>100001,'status'=>'bad'])->assertSessionHasErrors(['refinement_level','stat_increase_basis_points','status']);}}
